export default async function before(m, { conn, bot }) {
  // قائمة الكلمات اللي البوت هيراقبها والرياكتات الخاصة بكل كلمة
  const triggers = {
    // رادار باسمك يا ملك
    "أحمد": ["👑", "🦅", "⚡", "🫡", "🔥"],
    "المطور": ["💻", "🛰️", "⚙️", "💀", "🛡️"],
    
    // رادار ڤينوم وڤيني (تعديل الألوان والهيبة)
    "ڤينوم": ["🐍", "🕷️", "🖤", "🩸", "💀"],
    "ڤيني": ["🎼", "🎭", "🌌", "🪄", "🃏"],
    
    // رادار "المنبطحين" (لو حد غلط)
    "بوت": ["🤖", "🦾", "📡", "🔋", "⚠️"]
  };

  // لو النص اللي مبعوت موجود في القائمة
  if (triggers[m.text]) {
    // استخدمنا الـ random() اللي عرفناها في ملف الهوية فوق
    const emoji = triggers[m.text].random();
    
    // تنفيذ الرياكت فوراً
    await m.react(emoji);
  }
  
  return false;
}
